	YY_CHAR eckit_cmd__c = 1;
	if ( eckit_cmd__accept[eckit_cmd__current_state] )
		{
		(eckit_cmd__last_accepting_state) = eckit_cmd__current_state;
		(eckit_cmd__last_accepting_cpos) = eckit_cmd__cp;
		}
	while ( eckit_cmd__chk[eckit_cmd__base[eckit_cmd__current_state] + eckit_cmd__c] != eckit_cmd__current_state )
		{
		eckit_cmd__current_state = (int) eckit_cmd__def[eckit_cmd__current_state];
		if ( eckit_cmd__current_state >= 185 )
			eckit_cmd__c = eckit_cmd__meta[eckit_cmd__c];
		}
	eckit_cmd__current_state = eckit_cmd__nxt[eckit_cmd__base[eckit_cmd__current_state] + eckit_cmd__c];
	eckit_cmd__is_jam = (eckit_cmd__current_state == 184);

		return eckit_cmd__is_jam ? 0 : eckit_cmd__current_state;
