/** Immediately switch to a different input stream.
 * @param input_file A readable stream.
 * 
 * @note This function does not reset the start condition to @c INITIAL .
 */
    void eckit_cmd_restart  (FILE * input_file )
{
    
	if ( ! YY_CURRENT_BUFFER ){
        eckit_cmd_ensure_buffer_stack ();
		YY_CURRENT_BUFFER_LVALUE =
            eckit_cmd__create_buffer( eckit_cmd_in, YY_BUF_SIZE );
	}

	eckit_cmd__init_buffer( YY_CURRENT_BUFFER, input_file );
	eckit_cmd__load_buffer_state(  );
}

/** Switch to a different input buffer.
 * @param new_buffer The new input buffer.
 * 
 */
    void eckit_cmd__switch_to_buffer  (YY_BUFFER_STATE  new_buffer )
{
    
	/* TODO. We should be able to replace this entire function body
	 * with
	 *		eckit_cmd_pop_buffer_state();
	 *		eckit_cmd_push_buffer_state(new_buffer);
     */
	eckit_cmd_ensure_buffer_stack ();
	if ( YY_CURRENT_BUFFER == new_buffer )
		return;

	if ( YY_CURRENT_BUFFER )
		{
		/* Flush out information for old buffer. */
		*(eckit_cmd__c_buf_p) = (eckit_cmd__hold_char);
		YY_CURRENT_BUFFER_LVALUE->eckit_cmd__buf_pos = (eckit_cmd__c_buf_p);
		YY_CURRENT_BUFFER_LVALUE->eckit_cmd__n_chars = (eckit_cmd__n_chars);
		}

	YY_CURRENT_BUFFER_LVALUE = new_buffer;
	eckit_cmd__load_buffer_state(  );

	/* We don't actually know whether we did this switch during
	 * EOF (eckit_cmd_wrap()) processing, but the only time this flag
	 * is looked at is after eckit_cmd_wrap() is called, so it's safe
	 * to go ahead and always set it.
	 */
	(eckit_cmd__did_buffer_switch_on_eof) = 1;
}

static void eckit_cmd__load_buffer_state  (void)
{
    	(eckit_cmd__n_chars) = YY_CURRENT_BUFFER_LVALUE->eckit_cmd__n_chars;
	(eckit_cmd_text_ptr) = (eckit_cmd__c_buf_p) = YY_CURRENT_BUFFER_LVALUE->eckit_cmd__buf_pos;
	eckit_cmd_in = YY_CURRENT_BUFFER_LVALUE->eckit_cmd__input_file;
	(eckit_cmd__hold_char) = *(eckit_cmd__c_buf_p);
}

/** Allocate and initialize an input buffer state.
 * @param file A readable stream.
 * @param size The character buffer size in bytes. When in doubt, use @c YY_BUF_SIZE.
 * 
 * @return the allocated buffer state.
 */
    YY_BUFFER_STATE eckit_cmd__create_buffer  (FILE * file, int  size )
{
	YY_BUFFER_STATE b;
    
	b = (YY_BUFFER_STATE) eckit_cmd_alloc( sizeof( struct eckit_cmd__buffer_state )  );
	if ( ! b )
		YY_FATAL_ERROR( "out of dynamic memory in eckit_cmd__create_buffer()" );

	b->eckit_cmd__buf_size = size;

	/* eckit_cmd__ch_buf has to be 2 characters longer than the size given because
	 * we need to put in 2 end-of-buffer characters.
	 */
	b->eckit_cmd__ch_buf = (char *) eckit_cmd_alloc( (eckit_cmd__size_t) (b->eckit_cmd__buf_size + 2)  );
	if ( ! b->eckit_cmd__ch_buf )
		YY_FATAL_ERROR( "out of dynamic memory in eckit_cmd__create_buffer()" );

	b->eckit_cmd__is_our_buffer = 1;

	eckit_cmd__init_buffer( b, file );

	return b;
}

/** Destroy the buffer.
 * @param b a buffer created with eckit_cmd__create_buffer()
 * 
 */
    void eckit_cmd__delete_buffer (YY_BUFFER_STATE  b )
{
    
	if ( ! b )
		return;

	if ( b == YY_CURRENT_BUFFER ) /* Not sure if we should pop here. */
		YY_CURRENT_BUFFER_LVALUE = (YY_BUFFER_STATE) 0;

	if ( b->eckit_cmd__is_our_buffer )
		eckit_cmd_free( (void *) b->eckit_cmd__ch_buf  );

	eckit_cmd_free( (void *) b  );
}

/* Initializes or reinitializes a buffer.
 * This function is sometimes called more than once on the same buffer,
 * such as during a eckit_cmd_restart() or at EOF.
 */
    static void eckit_cmd__init_buffer  (YY_BUFFER_STATE  b, FILE * file )

{
	int oerrno = errno;
    
	eckit_cmd__flush_buffer( b );

	b->eckit_cmd__input_file = file;
	b->eckit_cmd__fill_buffer = 1;

    /* If b is the current buffer, then eckit_cmd__init_buffer was _probably_
     * called from eckit_cmd_restart() or through eckit_cmd__get_next_buffer.
     * In that case, we don't want to reset the lineno or column.
     */
    if (b != YY_CURRENT_BUFFER){
        b->eckit_cmd__bs_lineno = 1;
        b->eckit_cmd__bs_column = 0;
    }

        b->eckit_cmd__is_interactive = file ? (isatty( fileno(file) ) > 0) : 0;
    
	errno = oerrno;
}

/** Discard all buffered characters. On the next scan, YY_INPUT will be called.
 * @param b the buffer state to be flushed, usually @c YY_CURRENT_BUFFER.
 * 
 */
    void eckit_cmd__flush_buffer (YY_BUFFER_STATE  b )
{
    	if ( ! b )
		return;

	b->eckit_cmd__n_chars = 0;

	/* We always need two end-of-buffer characters.  The first causes
	 * a transition to the end-of-buffer state.  The second causes
	 * a jam in that state.
	 */
	b->eckit_cmd__ch_buf[0] = YY_END_OF_BUFFER_CHAR;
	b->eckit_cmd__ch_buf[1] = YY_END_OF_BUFFER_CHAR;

	b->eckit_cmd__buf_pos = &b->eckit_cmd__ch_buf[0];

	b->eckit_cmd__at_bol = 1;
	b->eckit_cmd__buffer_status = YY_BUFFER_NEW;

	if ( b == YY_CURRENT_BUFFER )
		eckit_cmd__load_buffer_state(  );
}

/** Pushes the new state onto the stack. The new state becomes
 *  the current state. This function will allocate the stack
 *  if necessary.
 *  @param new_buffer The new state.
 *  
 */
void eckit_cmd_push_buffer_state (YY_BUFFER_STATE new_buffer )
{
    	if (new_buffer == NULL)
		return;

	eckit_cmd_ensure_buffer_stack();

	/* This block is copied from eckit_cmd__switch_to_buffer. */
	if ( YY_CURRENT_BUFFER )
		{
		/* Flush out information for old buffer. */
		*(eckit_cmd__c_buf_p) = (eckit_cmd__hold_char);
		YY_CURRENT_BUFFER_LVALUE->eckit_cmd__buf_pos = (eckit_cmd__c_buf_p);
		YY_CURRENT_BUFFER_LVALUE->eckit_cmd__n_chars = (eckit_cmd__n_chars);
		}

	/* Only push if top exists. Otherwise, replace top. */
	if (YY_CURRENT_BUFFER)
		(eckit_cmd__buffer_stack_top)++;
	YY_CURRENT_BUFFER_LVALUE = new_buffer;

	/* copied from eckit_cmd__switch_to_buffer. */
	eckit_cmd__load_buffer_state(  );
	(eckit_cmd__did_buffer_switch_on_eof) = 1;
}

/** Removes and deletes the top of the stack, if present.
 *  The next element becomes the new top.
 *  
 */
void eckit_cmd_pop_buffer_state (void)
{
    	if (!YY_CURRENT_BUFFER)
		return;

	eckit_cmd__delete_buffer(YY_CURRENT_BUFFER );
	YY_CURRENT_BUFFER_LVALUE = NULL;
	if ((eckit_cmd__buffer_stack_top) > 0)
		--(eckit_cmd__buffer_stack_top);

	if (YY_CURRENT_BUFFER) {
		eckit_cmd__load_buffer_state(  );
		(eckit_cmd__did_buffer_switch_on_eof) = 1;
	}
}

/* Allocates the stack if it does not exist.
 *  Guarantees space for at least one push.
 */
static void eckit_cmd_ensure_buffer_stack (void)
{
	eckit_cmd__size_t num_to_alloc;
    
	if (!(eckit_cmd__buffer_stack)) {

		/* First allocation is just for 2 elements, since we don't know if this
		 * scanner will even need a stack. We use 2 instead of 1 to avoid an
		 * immediate realloc on the next call.
         */
      num_to_alloc = 1; /* After all that talk, this was set to 1 anyways... */
		(eckit_cmd__buffer_stack) = (struct eckit_cmd__buffer_state**)eckit_cmd_alloc
								(num_to_alloc * sizeof(struct eckit_cmd__buffer_state*)
								);
		if ( ! (eckit_cmd__buffer_stack) )
			YY_FATAL_ERROR( "out of dynamic memory in eckit_cmd_ensure_buffer_stack()" );

		memset((eckit_cmd__buffer_stack), 0, num_to_alloc * sizeof(struct eckit_cmd__buffer_state*));

		(eckit_cmd__buffer_stack_max) = num_to_alloc;
		(eckit_cmd__buffer_stack_top) = 0;
		return;
	}

	if ((eckit_cmd__buffer_stack_top) >= ((eckit_cmd__buffer_stack_max)) - 1){

		/* Increase the buffer to prepare for a possible push. */
		eckit_cmd__size_t grow_size = 8 /* arbitrary grow size */;

		num_to_alloc = (eckit_cmd__buffer_stack_max) + grow_size;
		(eckit_cmd__buffer_stack) = (struct eckit_cmd__buffer_state**)eckit_cmd_realloc
								((eckit_cmd__buffer_stack),
								num_to_alloc * sizeof(struct eckit_cmd__buffer_state*)
								);
		if ( ! (eckit_cmd__buffer_stack) )
			YY_FATAL_ERROR( "out of dynamic memory in eckit_cmd_ensure_buffer_stack()" );

		/* zero only the new slots.*/
		memset((eckit_cmd__buffer_stack) + (eckit_cmd__buffer_stack_max), 0, grow_size * sizeof(struct eckit_cmd__buffer_state*));
		(eckit_cmd__buffer_stack_max) = num_to_alloc;
	}
}

/** Setup the input buffer state to scan directly from a user-specified character buffer.
 * @param base the character buffer
 * @param size the size in bytes of the character buffer
 * 
 * @return the newly allocated buffer state object.
 */
YY_BUFFER_STATE eckit_cmd__scan_buffer  (char * base, eckit_cmd__size_t  size )
{
	YY_BUFFER_STATE b;
    
	if ( size < 2 ||
	     base[size-2] != YY_END_OF_BUFFER_CHAR ||
	     base[size-1] != YY_END_OF_BUFFER_CHAR )
		/* They forgot to leave room for the EOB's. */
		return NULL;

	b = (YY_BUFFER_STATE) eckit_cmd_alloc( sizeof( struct eckit_cmd__buffer_state )  );
	if ( ! b )
		YY_FATAL_ERROR( "out of dynamic memory in eckit_cmd__scan_buffer()" );

	b->eckit_cmd__buf_size = (int) (size - 2);	/* "- 2" to take care of EOB's */
	b->eckit_cmd__buf_pos = b->eckit_cmd__ch_buf = base;
	b->eckit_cmd__is_our_buffer = 0;
	b->eckit_cmd__input_file = NULL;
	b->eckit_cmd__n_chars = b->eckit_cmd__buf_size;
	b->eckit_cmd__is_interactive = 0;
	b->eckit_cmd__at_bol = 1;
	b->eckit_cmd__fill_buffer = 0;
	b->eckit_cmd__buffer_status = YY_BUFFER_NEW;

	eckit_cmd__switch_to_buffer( b  );

	return b;
}

/** Setup the input buffer state to scan a string. The next call to eckit_cmd_lex() will
 * scan from a @e copy of @a str.
 * @param eckit_cmd_str a NUL-terminated string to scan
 * 
 * @return the newly allocated buffer state object.
 * @note If you want to scan bytes that may contain NUL values, then use
 *       eckit_cmd__scan_bytes() instead.
 */
YY_BUFFER_STATE eckit_cmd__scan_string (const char * eckit_cmd_str )
{
    
	return eckit_cmd__scan_bytes( eckit_cmd_str, (int) strlen(eckit_cmd_str) );
}

/** Setup the input buffer state to scan the given bytes. The next call to eckit_cmd_lex() will
 * scan from a @e copy of @a bytes.
 * @param eckit_cmd_bytes the byte buffer to scan
 * @param _eckit_cmd_bytes_len the number of bytes in the buffer pointed to by @a bytes.
 * 
 * @return the newly allocated buffer state object.
 */
YY_BUFFER_STATE eckit_cmd__scan_bytes  (const char * eckit_cmd_bytes, int  _eckit_cmd_bytes_len )
{
	YY_BUFFER_STATE b;
	char *buf;
	eckit_cmd__size_t n;
	int i;
    
	/* Get memory for full buffer, including space for trailing EOB's. */
	n = (eckit_cmd__size_t) (_eckit_cmd_bytes_len + 2);
	buf = (char *) eckit_cmd_alloc( n  );
	if ( ! buf )
		YY_FATAL_ERROR( "out of dynamic memory in eckit_cmd__scan_bytes()" );

	for ( i = 0; i < _eckit_cmd_bytes_len; ++i )
		buf[i] = eckit_cmd_bytes[i];

	buf[_eckit_cmd_bytes_len] = buf[_eckit_cmd_bytes_len+1] = YY_END_OF_BUFFER_CHAR;

	b = eckit_cmd__scan_buffer( buf, n );
	if ( ! b )
		YY_FATAL_ERROR( "bad buffer in eckit_cmd__scan_bytes()" );

	/* It's okay to grow etc. this buffer, and we should throw it
	 * away when we're done.
	 */
	b->eckit_cmd__is_our_buffer = 1;

	return b;
}

